from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about astronauts (or related entities) into a
    fluent English sentence.  The function groups triples by their subject and
    builds a clause for each predicate, then joins the clauses into a single
    (or a few) readable sentences.
    """
    if not triples:
        return ""

    # Helper to turn a predicate/object pair into a descriptor (without repeating the subject)
    def phrase(subj: str, pred: str, obj: str) -> str:
        """Return a natural‑language descriptor for a single predicate."""
        obj = obj.strip().strip('"')
        p = pred.lower().replace(" ", "")
        def fmt_date(d: str) -> str:
            try:
                from datetime import datetime
                dt = datetime.strptime(d, "%Y-%m-%d")
                return dt.strftime("%B %-d, %Y")
            except Exception:
                return d

        if p == "birthdate":
            return f"was born on {fmt_date(obj)}"
        if p == "birthplace":
            return f"was born in {obj}"
        if p == "deathdate":
            return f"died on {fmt_date(obj)}"
        if p == "deathplace":
            return f"died in {obj}"
        if p == "dateofretirement":
            return f"retired on {fmt_date(obj)}"
        if p == "nationality":
            low_obj = obj.lower()
            if low_obj in ("united states", "usa", "united states of america"):
                return "is an American"
            if low_obj.startswith("the "):
                return f"is from {obj}"
            else:
                return f"is from the {obj}"
        if p == "occupation":
            return f"was a {obj.lower()}"
        if p == "status":
            low = obj.lower()
            if low == "retired":
                return "is retired"
            return f"is {low}"
        if p == "selectedbynasa":
            return f"was selected by NASA in {obj}"
        if p == "mission":
            return f"was a crew member of {obj}"
        if p == "timeinspace":
            try:
                mins = float(obj)
                hrs = int(mins // 60)
                rem = int(mins % 60)
                if hrs:
                    return f"spent {hrs} hour{'s' if hrs>1 else ''}" + (f" and {rem} minute{'s' if rem!=1 else ''}" if rem else "") + " in space"
                else:
                    return f"spent {rem} minute{'s' if rem!=1 else ''} in space"
            except Exception:
                return f"spent {obj} minutes in space"
        if p == "title":
            return f"held the title of {obj}"
        if p == "award":
            return f"received the {obj}"
        if p == "awards":
            return f"received {obj} awards"
        if p == "ribbonaward":
            return f"was awarded the {obj}"
        if p == "operator":
            return f"was operated by {obj}"
        if p == "commander":
            return f"{obj} was the commander of {subj}"
        if p == "backuppilot":
            return f"{subj}'s backup pilot was {obj}"
        if p == "crewmembers":
            return f"{obj} was a crew member of {subj}"
        if p == "alternativename":
            return f"is also known as {obj}"
        if p == "servedaschiefoftheastronautofficein":
            return f"served as Chief of the Astronaut Office in {obj}"
        if p == "representative":
            return f"{obj} was the representative of {subj}"
        if p == "bird":
            return f"The {obj.lower()} is a bird found in {subj}"
        # Generic fallback
        return f"is {obj}"

    # ----------------------------------------------------------------------
    # Pre‑process for special aggregations (mission ↔ crewMembers) and for
    # predicates that require subject‑object inversion (e.g., leader).
    # ----------------------------------------------------------------------
    from collections import defaultdict

    # 1️⃣ Aggregate mission‑related crew information
    mission_to_astronauts = defaultdict(list)   # subjects that have predicate 'mission'
    mission_to_crew = defaultdict(list)         # objects of predicate 'crewMembers'

    for t in triples:
        pred = t.predicate.lower()
        if pred == "mission":
            mission_to_astronauts[t.object].append(t.subject)
        elif pred == "crewmembers":
            mission_to_crew[t.subject].append(t.object)

    # Build sentences that combine both sources
    aggregated_sentences = []
    used_triples = set()   # indices of triples that have been expressed

    for mission, astro_list in mission_to_astronauts.items():
        crew_list = mission_to_crew.get(mission, [])
        all_astronauts = list(dict.fromkeys(astro_list + crew_list))  # preserve order, dedup

        if not all_astronauts:
            continue

        # mark related triples as used
        for i, t in enumerate(triples):
            if (t.predicate.lower() == "mission" and t.object == mission) or \
               (t.predicate.lower() == "crewmembers" and t.subject == mission):
                used_triples.add(i)

        if len(all_astronauts) == 1:
            agg = f"{all_astronauts[0]} was a crew member aboard {mission}"
        else:
            # Use “Both … and …” for two, otherwise list with commas and “and”
            if len(all_astronauts) == 2:
                names = f"{all_astronauts[0]} and {all_astronauts[1]}"
            else:
                names = ", ".join(all_astronauts[:-1]) + f", and {all_astronauts[-1]}"
            agg = f"Both {names} were crew members aboard {mission}"
        aggregated_sentences.append(agg)

    # 2️⃣ Group remaining triples by subject (excluding used ones)
    groups = defaultdict(list)
    for idx, t in enumerate(triples):
        if idx in used_triples:
            continue
        groups[t.subject].append(t)

    sentences = []

    for subj, items in groups.items():
        # Separate crewMembers triples to aggregate them (if any remain)
        crew_triples = [t for t in items if t.predicate.lower() == "crewMembers"]
        other_triples = [t for t in items if t.predicate.lower() != "crewMembers"]

        descriptors: list[str] = []
        full_sentences: list[str] = []

        for t in other_triples:
            # Special handling for predicates that need inversion
            if t.predicate.lower() == "leader":
                # subject is the entity (e.g., country), object is the person
                d = f"{t.object} is the {subj} leader"
            else:
                d = phrase(subj, t.predicate, t.object).strip()
            if subj.lower() in d.lower():
                full_sentences.append(d.rstrip('.'))
            else:
                descriptors.append(d.rstrip('.'))

        # Handle remaining crewMembers aggregation
        if crew_triples:
            members = [t.object.strip().strip('"') for t in crew_triples]
            if len(members) == 1:
                crew_desc = f"{members[0]} was a crew member of {subj}"
            else:
                crew_desc = f"{', '.join(members[:-1])} and {members[-1]} were crew members of {subj}"
            if subj.lower() in crew_desc.lower():
                full_sentences.append(crew_desc.rstrip('.'))
            else:
                descriptors.append(crew_desc.rstrip('.'))

        if descriptors:
            if len(descriptors) == 1:
                combined = f"{subj} {descriptors[0]}."
            else:
                if len(descriptors) == 2:
                    body = f"{descriptors[0]} and {descriptors[1]}"
                else:
                    body = ", ".join(descriptors[:-1]) + f", and {descriptors[-1]}"
                combined = f"{subj} {body}."
            sentences.append(combined)

        for s in full_sentences:
            sentences.append(s + ".")

    # Append the aggregated mission/crew sentences (they are already full sentences)
    sentences = aggregated_sentences + sentences

    # Combine all sentences into one paragraph
    return " ".join(sentences)

# EVOLVE-BLOCK-END
